{"path": "/tmp/sv-1a735dd4d765446c90c9be5ad7c8e0ca/Components/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@Title</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <BoardTaskCard Task="task"
                           ShowMoveLeft="ShowMoveLeft"
                           ShowMoveRight="ShowMoveRight"
                           OnMoveLeft="OnMoveLeft"
                           OnMoveRight="OnMoveRight" />
        }
    </div>
    <BoardAddTaskForm Status="@Status" OnTaskCreated="OnTaskCreated" />
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
}
"}

