{"path": "/tmp/sv-1a735dd4d765446c90c9be5ad7c8e0ca/Components/Board/BoardSearchBar.razor", "file_text": "<div class="search-bar">
    <input type="text" placeholder="Search tasks by title..." value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}
"}

