arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (errorMessage is not null)
{
    <div class="board-error">@errorMessage</div>
}
else if (allTasks is null)
{
    <div class="board-loading">Loading tasks…</div>
}
else
{
    <BoardStatsBar Total="@allTasks.Count"
                   ToDo="@GetByStatus("To Do").Count"
                   InProgress="@GetByStatus("In Progress").Count"
                   DoneCount="@GetByStatus("Done").Count"
                   Overdue="@allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn Title="To Do" Status="To Do"
                     Tasks="@FilterByStatus("To Do")"
                     ShowMoveLeft="false" ShowMoveRight="true"
                     OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="In Progress" Status="In Progress"
                     Tasks="@FilterByStatus("In Progress")"
                     ShowMoveLeft="true" ShowMoveRight="true"
                     OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                     OnMoveRight="@(t => MoveTask(t, "Done"))"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="Done" Status="Done"
                     Tasks="@FilterByStatus("Done")"
                     ShowMoveLeft="true" ShowMoveRight="false"
                     OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem>? allTasks;
    private string? errorMessage;
    private string searchText = "";

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
    }

    private List<TaskItem> GetByStatus(string status) =>
        allTasks!.Where(t => t.Status == status).ToList();

    private List<TaskItem> FilterByStatus(string status) =>
        allTasks!
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText)
                || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private void HandleSearchChanged(string text) => searchText = text;

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks!.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(TaskItem draft)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
            allTasks!.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

.board-loading,
.board-error {
    padding: 1rem;
    text-align: center;
}

.board-error {
    color: #dc3545;
    background: #f8d7da;
    border-radius: 6px;
}

.board-columns {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 6px;
    margin-bottom: 0.75rem;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.stat-label {
    font-size: 0.75rem;
    color: #6c757d;
    text-transform: uppercase;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

.search-bar {
    margin-bottom: 0.75rem;
}

.search-bar input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
}

.board-column {
    flex: 1;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 0.75rem;
    min-width: 250px;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #dee2e6;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
}

.column-count {
    background: #6c757d;
    color: #fff;
    border-radius: 50%;
    width: 1.5rem;
    height: 1.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.8rem;
    font-weight: 700;
}

.column-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-bottom: 0.75rem;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.65rem;
}

.task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

.task-assignee {
    margin: 0 0 0.35rem;
    font-size: 0.8rem;
    color: #6c757d;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
    margin-right: 0.4rem;
}

.priority-high {
    background: #dc3545;
}

.priority-medium {
    background: #ffc107;
    color: #212529;
}

.priority-low {
    background: #28a745;
}

.task-due {
    font-size: 0.8rem;
    color: #6c757d;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.4rem;
}

.btn-move {
    flex: 1;
    padding: 0.25rem 0.4rem;
    font-size: 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.btn-move:hover {
    background: #e9ecef;
}

.btn-add-task {
    width: 100%;
    padding: 0.4rem;
    border: 2px dashed #ced4da;
    border-radius: 6px;
    background: transparent;
    color: #6c757d;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-add-task:hover {
    border-color: #6c757d;
    color: #212529;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.65rem;
}

.add-task-form input,
.add-task-form select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.85rem;
}

.form-actions {
    display: flex;
    gap: 0.35rem;
}

.btn-save {
    flex: 1;
    padding: 0.35rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-cancel {
    flex: 1;
    padding: 0.35rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

